// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract TestContract {
    uint[] public numbers;

    function sumNumbers() public view returns (uint) {
        uint total = 0;
        for (uint i = 0; i < numbers.length; i++) {
            total += numbers[i];
        }
        return total;
    }
}
